import{_ as a,o as i,c as n,a2 as e}from"./chunks/framework.C24VBsJ9.js";const k=JSON.parse('{"title":"内核编译","description":"","frontmatter":{"title":"内核编译"},"headers":[],"relativePath":"tutorial/kernel/02_kernel_compile.md","filePath":"tutorial/kernel/02_kernel_compile.md","lastUpdated":1781369075000}'),l={name:"tutorial/kernel/02_kernel_compile.md"};function p(t,s,h,r,d,c){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="从0开始编译linux内核-当你发现make时少了一个包-第17次" tabindex="-1">从0开始编译Linux内核：当你发现make时少了一个包，第17次 <a class="header-anchor" href="#从0开始编译linux内核-当你发现make时少了一个包-第17次" aria-label="Permalink to &quot;从0开始编译Linux内核：当你发现make时少了一个包，第17次&quot;">​</a></h1><h2 id="为什么要写这篇编译教程" tabindex="-1">为什么要写这篇编译教程 <a class="header-anchor" href="#为什么要写这篇编译教程" aria-label="Permalink to &quot;为什么要写这篇编译教程&quot;">​</a></h2><p>你可能会想，Linux内核编译不是有现成的教程吗？随便一搜就是一堆。但我敢打赌，你第一次尝试的时候，至少会遇到以下问题之一：</p><ol><li>编译到一半报错，提示缺少某个头文件或工具（我当时就是我头文件呢？？？）</li><li>编译完成了，但产物是x86的，板子上跑不起来（孩子们记得ARCH=arm，少一下就完蛋）</li><li>想改配置，结果发现.config和defconfig的关系搞不清楚</li><li>编译完了一堆文件，不知道哪个是真正要用的</li></ol><p>我当年踩的坑比这还多。第一次编译内核，我直接用系统的gcc，结果编出来个x86_64的vmlinux，还奇怪怎么i.MX6ULL板子认不出来（一想到芯片对着X64的Instructions发懵我就想笑）。第二次好不容易用对了工具链，结果少了bc，make menuconfig直接报错。第三次装齐了依赖，编完了不知道怎么验证，直接把vmlinux往板子上拷，当然不行。</p><p>所以这篇文章的目标很明确：带你走一遍完整的内核编译流程，理解每一步在做什么、为什么这么做、可能会遇到什么坑。到了最后，你会明白这些步骤可以自动化，我会给你一个完整的build脚本——但那时候你已经理解了脚本的每一行在做什么。</p><h2 id="我们的工作环境" tabindex="-1">我们的工作环境 <a class="header-anchor" href="#我们的工作环境" aria-label="Permalink to &quot;我们的工作环境&quot;">​</a></h2><p>先说明一下本文的环境，避免踩不必要的坑：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平台：Ubuntu 24.04 LTS</span></span>
<span class="line"><span>目标板：i.MX6ULL 14x14 EVK (512MB DDR)</span></span>
<span class="line"><span>工具链：arm-none-linux-gnueabihf-gcc</span></span>
<span class="line"><span>内核版本：NXP linux-imx (lf-6.12.3)（哦对了，我上机测试是6.12.49，看来打了一些patch）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>环境不完全一样也没关系。Ubuntu 20.04/22.04 都可以，工具链只要是ARM硬浮点ABI的就行。内核版本主要影响配置选项，编译流程基本一致。</p><h2 id="准备工作-那些看似无关的包为什么必须装" tabindex="-1">准备工作：那些看似无关的包为什么必须装 <a class="header-anchor" href="#准备工作-那些看似无关的包为什么必须装" aria-label="Permalink to &quot;准备工作：那些看似无关的包为什么必须装&quot;">​</a></h2><p>在我们开始编译之前，先要把依赖装齐。这一步看起来简单，但缺了任何一个包，你都会在不同阶段遇到莫名其妙的报错。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    build-essential</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    bc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    bison</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    flex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    libssl-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    libgnutls28-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    libncurses-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    device-tree-compiler</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    python3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>我来逐项解释这些包都是干什么的。</p><p><code>build-essential</code>是基础构建工具包，包含了gcc、make、libc-dev这些编译必备的东西。没有它，你连最简单的C程序都编不过。</p><p><code>bc</code>是命令行计算器。你可能觉得奇怪，编译内核要计算器干嘛？答案在于Kconfig配置系统。内核的配置脚本会用到bc进行数值计算，比如计算内存大小、时钟分频比。没有bc，某些配置选项计算会报错。</p><p><code>bison</code>和<code>flex</code>是语法分析器生成工具。内核需要解析Kconfig配置文件，还需要生成某些驱动代码。这两者由flex（词法分析）和bison（语法分析）处理。你可能会在编译错误信息看到&quot;missing bison&quot;或&quot;missing flex&quot;，这就是缺这两个包的表现。</p><p><code>libssl-dev</code>和<code>libgnutls28-dev</code>是加密库开发文件。内核支持签名验证、加密的模块加载、安全启动等功能。这些功能需要OpenSSL或GnuTLS库。虽然不是严格必需，但为了完整性，建议装上。</p><p><code>libncurses-dev</code>是ncurses库的开发文件。ncurses是一个终端图形库，make menuconfig这种文本配置界面就是用它做的。没有它，你就没法用图形界面配置内核。</p><p><code>device-tree-compiler</code>也就是dtc，是设备树编译器。内核需要把.dts设备树源文件编译成.dtb二进制文件。虽然内核源码里自带了一个dtc，但系统安装一个版本更稳定，而且可以用于验证编译产物。</p><p><code>python3</code>是Python解释器。内核的某些构建脚本和工具是用Python写的，没有Python，编译可能会失败。</p><p>IMX-Forge项目的构建脚本<code>scripts/build_helper/build-linux.sh</code>会自动检查这些依赖。你运行脚本时，它会告诉你哪些包缺失，并给出安装命令。</p><h2 id="理解交叉编译-为什么不能直接用gcc" tabindex="-1">理解交叉编译：为什么不能直接用gcc <a class="header-anchor" href="#理解交叉编译-为什么不能直接用gcc" aria-label="Permalink to &quot;理解交叉编译：为什么不能直接用gcc&quot;">​</a></h2><p>现在我们来到第一个核心概念：交叉编译。很多新手在这里卡住，不明白为什么不能用系统的gcc直接编译。</p><p>问题很简单：你的开发机是x86_64架构的，而内核要跑在ARM架构的板子上。x86的CPU跑不了ARM指令，反之亦然。所以我们需要一个能运行在x86上、但生成ARM代码的编译器——这就是交叉编译器。</p><p>交叉编译器的命名规则是有规律的。以<code>arm-none-linux-gnueabihf-gcc</code>为例：</p><ul><li><code>arm</code>是目标架构</li><li><code>none</code>表示没有厂商（非嵌入式工具链）</li><li><code>linux</code>是目标操作系统</li><li><code>gnueabihf</code>是GNU EABI硬浮点ABI</li></ul><p>这里重点解释一下<code>gnueabihf</code>。ARM有两种浮点ABI：软浮点（gnueabi）和硬浮点（gnueabihf）。软浮点模式下，浮点运算用软件模拟，函数调用时整数和浮点参数都通过通用寄存器传递。硬浮点模式下，浮点运算用硬件FPU执行，浮点参数通过浮点寄存器传递。i.MX6ULL有硬件FPU，所以我们要用硬浮点工具链，性能更好。</p><p>获取交叉编译工具有几种方式。一种是直接从ARM官网下载预构建的工具链，另一种是用Ubuntu的包管理器安装（比如<code>gcc-arm-linux-gnueabihf</code>），还有一种是自己用crosstool-NG编译。对于初学者，推荐用前两种，省时省力。</p><p>安装好后，你可以用这个命令验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arm-none-linux-gnueabihf-gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果输出了版本信息，说明工具链在PATH里，可以正常使用。</p><h2 id="第一步-设置输出目录——为什么要分离源码和产物" tabindex="-1">第一步：设置输出目录——为什么要分离源码和产物 <a class="header-anchor" href="#第一步-设置输出目录——为什么要分离源码和产物" aria-label="Permalink to &quot;第一步：设置输出目录——为什么要分离源码和产物&quot;">​</a></h2><p>开始编译前，建议先设置一个独立的输出目录。这样可以保持源码目录干净，也方便清理。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> O</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/output/dir</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后在make时使用<code>O=输出目录</code>参数：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=/path/to/output/dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxx_defconfig</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=/path/to/output/dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>IMX-Forge项目的构建脚本使用固定的输出目录：<code>PROJECT_ROOT/out/linux</code>。这样所有的编译产物都在一个地方，管理起来很方便。</p><h2 id="第二步-defconfig——配置的魔法" tabindex="-1">第二步：defconfig——配置的魔法 <a class="header-anchor" href="#第二步-defconfig——配置的魔法" aria-label="Permalink to &quot;第二步：defconfig——配置的魔法&quot;">​</a></h2><p>清理完成后，我们需要配置内核：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_aes_defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里解释一下这三个变量的作用。<code>ARCH=arm</code>告诉内核目标架构是ARM，它会在<code>arch/arm/</code>目录下找架构相关代码。<code>CROSS_COMPILE=arm-none-linux-gnueabihf-</code>指定交叉编译器前缀。<code>O=out/linux</code>指定输出目录。</p><p><code>imx_aes_defconfig</code>是IMX-Forge项目为i.MX6ULL定制的默认配置。</p><blockquote><p><strong>⚠️ 重要提示</strong></p><p><code>imx_aes_defconfig</code> <strong>不是NXP官方提供的配置文件</strong>，而是IMX-Forge项目自定义的配置。 这个配置文件需要通过应用项目补丁后才会生成到linux-imx仓库中。</p><p><strong>使用方式：</strong></p><ol><li><p><strong>使用IMX-Forge构建系统（推荐）</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/build_helper/build-linux.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 自动应用补丁并构建</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>手动操作：需要先应用补丁</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> third_party/linux-imx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../../patches/linux-imx/linux-imx-latest.patch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=../../out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_aes_defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>NXP官方仓库：使用官方配置</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_v7_defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol></blockquote><p>IMX-Forge项目应用补丁后，defconfig文件位于<code>arch/arm/configs/</code>目录下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arch/arm/configs/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">├──</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_aes_defconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # IMX-Forge 自定义配置（应用补丁后）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">├──</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_v6_v7_defconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # NXP 官方：i.MX 6/7系列通用配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">├──</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imx_v7_defconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # NXP 官方：i.MX 7系列配置（推荐用于i.MX6ULL）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">└──</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>defconfig不是.config的完整复制，它只存储与默认值不同的配置选项。举个例子，如果某个配置项默认是n，板子需要它设为y，defconfig里就只会记录<code>CONFIG_XXX=y</code>。</p><p>当你运行<code>make xxx_defconfig</code>时，内核会做这几件事：</p><ol><li>加载指定的defconfig</li><li>处理Kconfig文件（评估所有配置符号、依赖和默认值）</li><li>生成完整的.config文件</li></ol><p>所以.config是defconfig + Kconfig系统共同作用的结果，不是简单的复制粘贴。</p><p>配置完成后，.config文件会出现在输出目录（<code>out/linux/.config</code>）。这个文件是编译时实际使用的配置，包含了完整的配置信息（默认值 + 板级特定设置）。</p><h2 id="第三步-make——并行编译的威力" tabindex="-1">第三步：make——并行编译的威力 <a class="header-anchor" href="#第三步-make——并行编译的威力" aria-label="Permalink to &quot;第三步：make——并行编译的威力&quot;">​</a></h2><p>配置完成后，终于可以编译了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>-j$(nproc)</code>这个参数很重要。<code>nproc</code>命令会输出CPU核心数，<code>-j</code>告诉make可以并行运行这么多任务。现代CPU都是多核的，不利用并行编译就太浪费了。我电脑是8核，<code>make -j8</code>基本上几分钟就编完了。</p><p>编译过程做了这些事情：</p><ol><li>编译C源文件生成.o目标文件</li><li>链接生成vmlinux ELF文件</li><li>解析vmlinux生成System.map符号表</li><li>用objcopy转换格式生成Image（纯二进制）</li><li>压缩Image生成zImage</li><li>打包zImage+设备树生成最终镜像</li></ol><p>编译过程可能需要几分钟到十几分钟，取决于你的CPU性能和配置。</p><h2 id="编译产物说明-一堆文件都是干什么用的" tabindex="-1">编译产物说明：一堆文件都是干什么用的 <a class="header-anchor" href="#编译产物说明-一堆文件都是干什么用的" aria-label="Permalink to &quot;编译产物说明：一堆文件都是干什么用的&quot;">​</a></h2><p>编译完成后，你会在输出目录看到这些文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/linux/</span></span>
<span class="line"><span>├── vmlinux                     # ELF格式的内核镜像</span></span>
<span class="line"><span>├── System.map                  # 符号地址表</span></span>
<span class="line"><span>├── .config                     # 内核配置</span></span>
<span class="line"><span>├── arch/arm/boot/</span></span>
<span class="line"><span>│   ├── Image                   # 未压缩的内核镜像</span></span>
<span class="line"><span>│   └── zImage                  # 压缩的内核镜像</span></span>
<span class="line"><span>└── modules/                    # 内核模块（如果编译了模块）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="vmlinux-elf格式的完整内核" tabindex="-1">vmlinux：ELF格式的完整内核 <a class="header-anchor" href="#vmlinux-elf格式的完整内核" aria-label="Permalink to &quot;vmlinux：ELF格式的完整内核&quot;">​</a></h3><p><code>vmlinux</code>是ELF格式的可执行文件，带调试信息，通常有几十MB。这个文件包含了完整的内核代码和数据，但太大且是ELF格式，不能直接烧录到板子上。它主要用于调试。</p><p>vmlinux的名字有点意思：vm = virtual memory（虚拟内存），linux = Linux内核。早期的Linux内核需要虚拟内存支持，所以叫vmlinux，这个名字一直沿用到现在。</p><h3 id="image-纯二进制格式" tabindex="-1">Image：纯二进制格式 <a class="header-anchor" href="#image-纯二进制格式" aria-label="Permalink to &quot;Image：纯二进制格式&quot;">​</a></h3><p><code>arch/arm/boot/Image</code>是vmlinux去掉ELF头和调试信息后的纯二进制格式，大约5-10MB。这个可以直接加载到内存运行，但因为没有压缩，占用空间较大。</p><h3 id="zimage-自解压的压缩镜像" tabindex="-1">zImage：自解压的压缩镜像 <a class="header-anchor" href="#zimage-自解压的压缩镜像" aria-label="Permalink to &quot;zImage：自解压的压缩镜像&quot;">​</a></h3><p><code>arch/arm/boot/zImage</code>是Image经过gzip压缩后，加上自解压代码的镜像，大约2-5MB。这是最常用的格式——体积小，加载到内存后会自动解压。</p><p>zImage的名字：z = gzip压缩。类似的还有bzImage（big zImage，用于x86的大内核）。</p><p>对于嵌入式系统，zImage通常是最终烧录的文件。</p><h3 id="system-map-符号地址表" tabindex="-1">System.map：符号地址表 <a class="header-anchor" href="#system-map-符号地址表" aria-label="Permalink to &quot;System.map：符号地址表&quot;">​</a></h3><p><code>System.map</code>是内核符号及其地址的映射表。它的格式是：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c0008000 T _text</span></span>
<span class="line"><span>c0008000 A stext</span></span>
<span class="line"><span>c0008000 t _head</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>每一行表示一个符号的地址、类型、名称。当内核出现Oops（崩溃）时，会打印出错的地址，你可以用System.map找到对应的函数名，帮助定位问题。</p><h3 id="config-配置文件" tabindex="-1">.config：配置文件 <a class="header-anchor" href="#config-配置文件" aria-label="Permalink to &quot;.config：配置文件&quot;">​</a></h3><p><code>.config</code>是编译时使用的完整配置。它非常重要，因为不同的配置会产生不同的内核。建议把.config保存好，下次编译时直接用，这样可以保证配置一致。</p><h3 id="dtb-设备树blob" tabindex="-1">.dtb：设备树Blob <a class="header-anchor" href="#dtb-设备树blob" aria-label="Permalink to &quot;.dtb：设备树Blob&quot;">​</a></h3><p>如果你编译了设备树，还会看到.dtb文件。设备树编译后的二进制格式，包含了硬件描述。U-Boot加载内核时，会把dtb地址传给内核，内核根据dtb初始化硬件。</p><h2 id="产物验证-如何确认编译没白忙活" tabindex="-1">产物验证：如何确认编译没白忙活 <a class="header-anchor" href="#产物验证-如何确认编译没白忙活" aria-label="Permalink to &quot;产物验证：如何确认编译没白忙活&quot;">​</a></h2><p>编译完成了，但我们还不能高兴得太早。你需要验证产物是否正确，不然烧到板子上发现起不来，排查起来更麻烦。</p><h3 id="架构检查-用readelf看清真相" tabindex="-1">架构检查：用readelf看清真相 <a class="header-anchor" href="#架构检查-用readelf看清真相" aria-label="Permalink to &quot;架构检查：用readelf看清真相&quot;">​</a></h3><p>首先检查架构是否正确：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arm-none-linux-gnueabihf-readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/linux/vmlinux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Machine</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Machine: ARM</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果不是ARM，说明你用错了工具链，白忙活了。我见过有人用aarch64工具链编译armv7代码，产物架构不对，板子上当然跑不起来。</p><p>除了架构，还可以看入口地址：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arm-none-linux-gnueabihf-readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/linux/vmlinux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Entry point&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出类似：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entry point address: 0xc0008000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个地址是内核在虚拟内存中的入口点。对于ARM，0xc0008000是经典的内核加载地址（物理地址0x80000000的虚拟映射）。</p><h3 id="大小检查-合理范围的验证" tabindex="-1">大小检查：合理范围的验证 <a class="header-anchor" href="#大小检查-合理范围的验证" aria-label="Permalink to &quot;大小检查：合理范围的验证&quot;">​</a></h3><p>检查zImage的大小：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/linux/arch/arm/boot/zImage</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出类似：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-rwxr-xr-x 1 user user 3.2M Mar 15 12:34 out/linux/arch/arm/boot/zImage</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>i.MX6ULL的内核zImage一般在2-5MB之间。如果小于1MB，可能编译不完整；如果大于10MB，可能配置了太多调试选项或不必要的驱动。</p><h3 id="符号检查-system-map是否正确" tabindex="-1">符号检查：System.map是否正确 <a class="header-anchor" href="#符号检查-system-map是否正确" aria-label="Permalink to &quot;符号检查：System.map是否正确&quot;">​</a></h3><p>检查System.map是否包含预期的符号：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/linux/System.map</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c0008000 T _text</span></span>
<span class="line"><span>c0008000 A stext</span></span>
<span class="line"><span>c0008000 t _head</span></span>
<span class="line"><span>c0008000 t _start</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果System.map是空的或只有几行，说明编译出了问题。</p><h3 id="设备树验证-dtc反编译" tabindex="-1">设备树验证：dtc反编译 <a class="header-anchor" href="#设备树验证-dtc反编译" aria-label="Permalink to &quot;设备树验证：dtc反编译&quot;">​</a></h3><p>如果你编译了设备树，可以验证一下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dtc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dtb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/arm/boot/dts/imx6ull-14x14-evk.dtb</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fsl,imx6ull</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该能看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>compatible = &quot;fsl,imx6ull&quot;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果看不到imx6ull的字样，说明设备树可能选错了。</p><h2 id="常见编译错误及解决" tabindex="-1">常见编译错误及解决 <a class="header-anchor" href="#常见编译错误及解决" aria-label="Permalink to &quot;常见编译错误及解决&quot;">​</a></h2><p>编译内核时，常见错误有这几类。我整理了一下，方便你快速排查。</p><h3 id="错误1-缺少依赖包" tabindex="-1">错误1：缺少依赖包 <a class="header-anchor" href="#错误1-缺少依赖包" aria-label="Permalink to &quot;错误1：缺少依赖包&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/kconfig/conf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --syncconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/bin/sh:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bc:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> not</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> found</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ***</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [Makefile:xxx: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">syncconfig]</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Error</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这是缺少bc包。安装方法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>类似的错误还可能出现在bison、flex、openssl等包上。</p><h3 id="错误2-架构错误" tabindex="-1">错误2：架构错误 <a class="header-anchor" href="#错误2-架构错误" aria-label="Permalink to &quot;错误2：架构错误&quot;">​</a></h3><p>如果你看到类似的警告：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WARNING: vmlinux.o (.text+0x...): unexpected relocation</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可能是ARCH设错了，或者工具链不匹配。检查一下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ARCH</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arm-none-linux-gnueabihf-gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>确保ARCH=arm，工具链是ARM的。</p><h3 id="错误3-配置冲突" tabindex="-1">错误3：配置冲突 <a class="header-anchor" href="#错误3-配置冲突" aria-label="Permalink to &quot;错误3：配置冲突&quot;">​</a></h3><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: attempt to assign twice to &#39;CONFIG_XXX&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这通常是.config里有冲突的配置。解决方法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> distclean</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxx_defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>先清理，再重新配置。</p><h3 id="错误4-空间不足" tabindex="-1">错误4：空间不足 <a class="header-anchor" href="#错误4-空间不足" aria-label="Permalink to &quot;错误4：空间不足&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">No</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> space</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> device</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>内核编译需要不少临时文件空间，确保你的磁盘有足够空间（至少2GB）。可以用<code>df -h</code>检查。</p><h2 id="总结成脚本-方便起见-我们把它自动化" tabindex="-1">总结成脚本：方便起见，我们把它自动化 <a class="header-anchor" href="#总结成脚本-方便起见-我们把它自动化" aria-label="Permalink to &quot;总结成脚本：方便起见，我们把它自动化&quot;">​</a></h2><p>到这里，你应该已经掌握了内核编译的完整流程。但每次都要敲这么多命令，确实有点累。而且容易出错，比如忘了distclean导致配置不生效，或者ARCH和CROSS_COMPILE写错了。</p><p>所以我们把这些步骤总结成一个脚本。IMX-Forge项目的<code>scripts/build_helper/build-linux.sh</code>就是这么一个脚本，它做了几件事：</p><ol><li>检查主机依赖（build-essential、bc、bison等）</li><li>检查交叉编译工具链</li><li>检查defconfig文件是否存在</li><li>执行distclean/configure/build三阶段编译</li><li>验证编译产物</li></ol><p>使用方法很简单：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/imx-forge</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/build_helper/build-linux.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>脚本会自动处理所有细节，你只需要坐等编译完成。</p><h2 id="快速编译技巧-节省时间的实用方法" tabindex="-1">快速编译技巧：节省时间的实用方法 <a class="header-anchor" href="#快速编译技巧-节省时间的实用方法" aria-label="Permalink to &quot;快速编译技巧：节省时间的实用方法&quot;">​</a></h2><p>当你频繁修改和编译时，全量编译太浪费时间。这里有几个加速技巧。</p><h3 id="只编译修改的部分" tabindex="-1">只编译修改的部分 <a class="header-anchor" href="#只编译修改的部分" aria-label="Permalink to &quot;只编译修改的部分&quot;">​</a></h3><p>如果你只修改了某个驱动，可以只编译这个驱动：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drivers/gpio/gpio-mxc.o</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="跳过模块编译" tabindex="-1">跳过模块编译 <a class="header-anchor" href="#跳过模块编译" aria-label="Permalink to &quot;跳过模块编译&quot;">​</a></h3><p>如果你不需要内核模块，可以禁用它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=arm-none-linux-gnueabihf-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O=out/linux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CONFIG_MODULES=n</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="使用ccache" tabindex="-1">使用ccache <a class="header-anchor" href="#使用ccache" aria-label="Permalink to &quot;使用ccache&quot;">​</a></h3><p>ccache是编译器缓存，第二次编译相同代码时直接用缓存，大幅提速：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ccache</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CROSS_COMPILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ccache arm-none-linux-gnueabihf-&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>IMX-Forge的构建脚本支持<code>--fast-build</code>参数，跳过distclean，节省时间。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>到这里，Linux内核编译的完整流程你就掌握了。从手动敲命令到理解每个步骤的含义，从排查错误到自动化脚本，我们走完了整个旅程。</p><p>编译不是黑魔法，每一步都有它的原因。distclean是为了避免缓存毒药，defconfig是通过Kconfig生成配置，make -j$(nproc)是利用多核加速，产物验证是确保没白忙活。当你理解了这些，你就不是在机械地复制命令，而是在掌控整个构建过程。</p><p>但编译只是第一步。下一篇文章，我们将深入内核配置的世界。你会看到：</p><ul><li>defconfig和.config到底有什么区别</li><li>menuconfig怎么用</li><li>哪些配置项是必须了解的</li><li>如何创建自己的defconfig</li></ul><p>准备好了吗？我们来配置内核。</p><hr><p><strong>延伸阅读</strong></p><ul><li><a href="https://www.kernel.org/doc/html/latest/kbuild/index.html" target="_blank" rel="noreferrer">Linux Kernel Build Documentation</a> - 内核构建系统文档</li><li><a href="https://www.kernel.org/doc/html/latest/kbuild/llvm.html" target="_blank" rel="noreferrer">Cross-Compilation with gcc</a> - 交叉编译指南</li></ul>`,158)])])}const u=a(l,[["render",p]]);export{k as __pageData,u as default};
